'use server'

import { createAdminClient } from '@/lib/supabase/server'

export async function backfillUsernames() {
    const supabase = await createAdminClient()

    // Get all profiles without username
    console.log('💎 Starting Diamond Backfill for usernames...')
    const { data: profiles, error } = await supabase
        .from('profiles')
        .select('id, email')
        .is('username', null)

    if (error) {
        console.error('❌ Diamond Backfill Error:', error)
        return { success: false, error: error.message }
    }

    console.log(`💎 Found ${profiles?.length || 0} profiles needing backfill.`)

    if (!profiles || profiles.length === 0) return { success: true, count: 0 }

    let backfilledCount = 0
    for (const profile of profiles) {
        if (!profile.email) continue

        let baseUsername = profile.email.split('@')[0].toLowerCase().replace(/[^a-z0-9]/g, '-')
        let username = baseUsername
        let counter = 0

        // Ensure uniqueness (basic check)
        const { data: existing } = await supabase
            .from('profiles')
            .select('id')
            .eq('username', username)
            .maybeSingle()

        if (existing) {
            counter++
            username = `${baseUsername}${counter}`
            // Simple loop protection
            if (counter > 10) break
        }

        console.log(`💎 Attempting to update profile ${profile.id} with username: ${username}`)
        const { error: updateError } = await supabase
            .from('profiles')
            .update({ username })
            .eq('id', profile.id)

        if (updateError) {
            console.error(`❌ Failed to update profile ${profile.id}:`, updateError)
        } else {
            console.log(`✅ Successfully backfilled profile ${profile.id} with username: ${username}`)
            backfilledCount++
        }
    }

    // Final check for currently logged in user to avoid stale state
    const { data: { user: currentUser } } = await supabase.auth.getUser()
    if (currentUser) {
        console.log(`💎 Diamond Investigation: Checking session user ${currentUser.id}`)
        const { data: currProfile } = await supabase.from('profiles').select('username').eq('id', currentUser.id).maybeSingle()
        if (currProfile && !currProfile.username) {
            console.log('💎 Diamond: Forcing username for current user session...')
            const newUsername = 'user-' + Math.random().toString(36).substring(2, 7)
            await supabase.from('profiles').update({ username: newUsername }).eq('id', currentUser.id)
            return { success: true, count: 1, message: 'Force synced current user' }
        }
    }

    console.log(`💎 Diamond Backfill complete. Total users updated: ${backfilledCount}`)
    return { success: true, count: backfilledCount }
}

import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import DashboardClient from '@/components/dashboard/dashboard-client'

export default async function DashboardPage() {
    try {
        const supabase = await createClient()
        const { data: { user }, error: authError } = await supabase.auth.getUser()

        if (authError || !user) {
            redirect('/login')
        }

        const [{ data: profile, error: profileError }, { data: meetings, error: meetingsError }] = await Promise.all([
            supabase
                .from('profiles')
                .select('id, full_name, personal_meeting_id')
                .eq('id', user.id)
                .maybeSingle(),
            supabase
                .from('meetings')
                .select('*')
                .eq('host_id', user.id)
                .order('start_time', { ascending: true })
        ])

        if (profileError) console.error("Error fetching dashboard profile:", profileError)
        if (meetingsError) console.error("Error fetching dashboard meetings:", meetingsError)

        return <DashboardClient
            user={user}
            profile={profile || { id: user.id, full_name: null, personal_meeting_id: null }}
            meetings={meetings || []}
            isDemo={false}
        />
    } catch (err) {
        console.error("CRITICAL ERROR IN DASHBOARD PAGE:", err)
        // Redireciona para login ou mostra uma mensagem de erro controlada
        // Para evitar loop de redirecionamento se o problema for no middleware:
        return (
            <div className="min-h-screen flex items-center justify-center bg-[#020617] text-white p-6">
                <div className="max-w-md w-full space-y-4 text-center">
                    <h1 className="text-2xl font-bold text-red-500">Erro de Conexão</h1>
                    <p className="text-gray-400">Não foi possível carregar o dashboard. Por favor, verifique sua conexão ou tente novamente mais tarde.</p>
                    <a href="/login" className="inline-block mt-4 text-cyan-500 hover:text-cyan-400 font-bold uppercase tracking-widest text-xs">Voltar para Login</a>
                </div>
            </div>
        )
    }
}

'use client'

import { useState, useEffect, Suspense } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { useRouter, useSearchParams } from 'next/navigation'
import Link from 'next/link'
import { AlertCircle, Loader2, Zap, Eye, EyeOff, CheckCircle2 } from 'lucide-react'
import { Logo } from '@/components/logo'
import { login } from './actions'
import { motion, AnimatePresence } from 'framer-motion'
import { useLanguage } from '@/components/providers/language-provider'

function LoginForm() {
    const { t } = useLanguage()
    const [email, setEmail] = useState('')
    const [emailError, setEmailError] = useState(false)
    const [password, setPassword] = useState('')
    const [showPassword, setShowPassword] = useState(false)
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const router = useRouter()
    const searchParams = useSearchParams()

    useEffect(() => {
        const errorType = searchParams.get('error')
        const status = searchParams.get('status')

        if (errorType === 'account_locked' || errorType === 'access_denied') {
            // Delay state update to avoid synchronous render warning
            const timer = setTimeout(() => {
                if (status === 'banned') {
                    setError('login_error_banned')
                } else if (status === 'suspended') {
                    setError('login_error_suspended')
                } else {
                    setError('login_error_denied')
                }
            }, 0)
            return () => clearTimeout(timer)
        } else if (errorType === 'connection_timeout') {
            setError('login_error_timeout')
        }
    }, [searchParams])

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault()
        setLoading(true)
        setError(null)

        const cleanEmail = email.trim()

        // Basic client-side sanitization/validation
        if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(cleanEmail)) {
            setError('login_error_email')
            setEmailError(true)
            setLoading(false)
            return
        }

        const formData = new FormData()
        formData.append('email', cleanEmail)
        formData.append('password', password)

        const result = await login(formData)

        if (result && !result.success) {
            setError(result.error || 'Erro inesperado')
            setLoading(false)
        }
        // Result is undefined if redirect happens, which is handled by Next.js
    }

    return (
        <div className="min-h-screen flex items-center justify-center bg-[#020617] relative overflow-hidden p-6">
            {/* Background Base */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(8,145,178,0.08),transparent_70%)] pointer-events-none" />
            <div className="absolute inset-0 bg-[url('/grid.svg')] bg-center [mask-image:radial-gradient(ellipse_at_center,black,transparent_80%)] opacity-10 pointer-events-none" />

            {/* MAIN LOGIN CONTAINER (STANDARD & CLEAN) */}
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, ease: "easeOut" }}
                className="w-full max-w-md z-30 relative"
            >
                {/* Central Logo */}
                <div className="mb-12 flex justify-center">
                    <Logo className="scale-110" />
                </div>

                <div className="bg-white/[0.03] backdrop-blur-3xl border border-white/10 p-10 rounded-[2.5rem] shadow-[0_32px_64px_-16px_rgba(0,0,0,0.5)] relative overflow-hidden">
                    {/* Subtle internal glow */}
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-1/2 h-px bg-gradient-to-r from-transparent via-cyan-500/20 to-transparent" />

                    <div className="space-y-2 mb-10 text-center">
                        <h1 className="text-3xl font-bold tracking-tight text-white uppercase italic">
                            {t('landing.login_title')}
                        </h1>
                        <p className="text-gray-500 text-sm">
                            {t('landing.login_subtitle')}
                        </p>
                    </div>

                    <form className="space-y-6" onSubmit={handleLogin}>
                        <div className="space-y-5">
                            <div className="space-y-2">
                                <Label htmlFor="email" className="text-xs font-bold text-gray-500 uppercase tracking-widest ml-1">
                                    {t('landing.login_email_label')}
                                </Label>
                                <div className="relative group">
                                    <Input
                                        id="email"
                                        name="email"
                                        type="email"
                                        autoComplete="email"
                                        required
                                        className="bg-black/40 border-white/5 text-white h-14 px-5 rounded-2xl focus:ring-cyan-500/20 focus:border-cyan-500/50 transition-all placeholder:text-gray-700"
                                        placeholder="exemplo@empresa.com"
                                        value={email}
                                        onChange={(e) => {
                                            setEmail(e.target.value)
                                            if (emailError) setEmailError(false)
                                        }}
                                    />
                                    <div className="absolute inset-x-0 bottom-0 h-[2px] bg-gradient-to-r from-transparent via-cyan-500/50 to-transparent scale-x-0 group-focus-within:scale-x-100 transition-transform duration-700" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <div className="flex justify-between items-center ml-1">
                                    <Label htmlFor="password" className="text-xs font-bold text-gray-500 uppercase tracking-widest">
                                        {t('landing.login_password_label')}
                                    </Label>
                                    <Link href="/auth/forgot-password" title="Esqueceu?" className="text-[10px] text-cyan-500/70 hover:text-cyan-400 transition-colors font-bold uppercase tracking-tighter">
                                        {t('landing.login_forgot_password')}
                                    </Link>
                                </div>
                                <div className="relative group">
                                    <Input
                                        id="password"
                                        name="password"
                                        type={showPassword ? "text" : "password"}
                                        autoComplete="current-password"
                                        required
                                        className="bg-black/40 border-white/5 text-white h-14 px-5 pr-14 rounded-2xl focus:ring-cyan-500/20 focus:border-cyan-500/50 transition-all placeholder:text-gray-700"
                                        placeholder="••••••••"
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPassword(!showPassword)}
                                        className="absolute right-5 top-1/2 -translate-y-1/2 text-gray-600 hover:text-cyan-400 transition-colors p-1"
                                    >
                                        {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                                    </button>
                                    <div className="absolute inset-x-0 bottom-0 h-[2px] bg-gradient-to-r from-transparent via-cyan-500/50 to-transparent scale-x-0 group-focus-within:scale-x-100 transition-transform duration-700" />
                                </div>
                            </div>
                        </div>

                        <AnimatePresence mode="wait">
                            {error && (
                                <motion.div
                                    initial={{ opacity: 0, height: 0 }}
                                    animate={{ opacity: 1, height: 'auto' }}
                                    exit={{ opacity: 0, height: 0 }}
                                    className="bg-red-500/10 border border-red-500/20 rounded-2xl p-4 flex items-center gap-3 text-red-400 text-xs font-medium"
                                >
                                    <AlertCircle className="h-4 w-4 flex-shrink-0" />
                                    <span>{error.startsWith('login_error_') ? (t(`landing.${error}` as any)) : error}</span>
                                </motion.div>
                            )}
                        </AnimatePresence>

                        <Button
                            type="submit"
                            className="w-full bg-cyan-600 hover:bg-cyan-500 text-white font-black h-14 rounded-2xl transition-all shadow-[0_20px_40px_-12px_rgba(8,145,178,0.4)] hover:shadow-[0_24px_48px_-12px_rgba(8,145,178,0.5)] hover:-translate-y-1 active:translate-y-0 disabled:opacity-70 text-lg uppercase tracking-tighter"
                            disabled={loading}
                        >
                            {loading ? <Loader2 className="h-6 w-6 animate-spin" /> : t('landing.login_button')}
                        </Button>
                    </form>

                    <div className="mt-12 text-center">
                        <Link href="/contact" className="text-[11px] font-bold text-gray-500 hover:text-cyan-400 transition-all uppercase tracking-[0.2em] group">
                            {t('landing.login_no_account')} <span className="text-white group-hover:text-cyan-400 underline decoration-cyan-500/30 underline-offset-4 decoration-2">{t('landing.login_contact_sales')}</span>
                        </Link>
                    </div>
                </div>
            </motion.div>

            {/* Fixed Bottom Left: Copyright (Editorial feel) */}
            <div className="fixed bottom-8 left-8 text-[10px] text-gray-600 font-bold uppercase tracking-[0.3em] font-mono pointer-events-none hidden xl:block">
                © 2025 TALKTUBE CORP. / ALL RIGHTS RESERVED
            </div>
        </div>
    )
}

export default function LoginPage() {
    return (
        <Suspense fallback={
            <div className="min-h-screen flex items-center justify-center bg-[#020817]">
                <Loader2 className="h-8 w-8 text-[#06b6d4] animate-spin" />
            </div>
        }>
            <LoginForm />
        </Suspense>
    )
}

"use client"

import { MessageCircle } from "lucide-react"
import { motion, AnimatePresence } from "framer-motion"
import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"

import { useLanguage } from '@/components/providers/language-provider'

interface FloatingWhatsAppProps {
    alwaysVisible?: boolean
    type?: 'sales' | 'support'
}

export function FloatingWhatsApp({ alwaysVisible = false, type = 'sales' }: FloatingWhatsAppProps) {
    const { t } = useLanguage()
    const [isVisible, setIsVisible] = useState(alwaysVisible)

    // Select message based on type
    const messageKey = type === 'support' ? 'common.whatsapp_msg_support' : 'common.whatsapp_msg_sales'
    const message = t(messageKey)
    const encodedMessage = encodeURIComponent(message)
    const whatsappUrl = `https://api.whatsapp.com/send?phone=5511998274824&text=${encodedMessage}`

    useEffect(() => {
        if (alwaysVisible) {
            setIsVisible(true)
            return
        }

        const handleScroll = () => {
            if (window.scrollY > 300) {
                setIsVisible(true)
            } else {
                setIsVisible(false)
            }
        }

        window.addEventListener("scroll", handleScroll)
        return () => window.removeEventListener("scroll", handleScroll)
    }, [alwaysVisible])

    return (
        <AnimatePresence>
            {isVisible && (
                <motion.a
                    href={whatsappUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    suppressHydrationWarning
                    initial={{ opacity: 0, scale: 0.8, y: 20 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.8, y: 20 }}
                    whileHover={{ scale: 1.1 }}
                    className="fixed bottom-6 right-6 z-50 flex items-center gap-2 bg-[#25D366] hover:bg-[#20bd5a] text-white px-4 py-3 rounded-full shadow-[0_4px_12px_rgba(37,211,102,0.4)] font-medium transition-colors"
                >
                    <MessageCircle className="w-6 h-6 fill-current" />
                    <span className="hidden sm:inline">{t('common.whatsapp_button')}</span>
                </motion.a>
            )}
        </AnimatePresence>
    )
}

