"use client"

import { Menu } from "lucide-react";
import { Sheet, SheetContent, SheetTrigger } from "@/components/ui/sheet";
import { Sidebar } from "@/components/sidebar";
import { Button } from "@/components/ui/button";
import { useState, useEffect } from "react";
import { usePathname } from "next/navigation";

interface MobileSidebarProps {
    user: Record<string, unknown> & { id?: string }
    userRole: string;
    userAvatar?: string | null;
    userName?: string;
}

export const MobileSidebar = ({ user, userRole, userAvatar, userName }: MobileSidebarProps) => {
    const [isMounted, setIsMounted] = useState(false);
    const pathname = usePathname();
    const [open, setOpen] = useState(false);

    useEffect(() => {
        setIsMounted(true);
    }, []);

    useEffect(() => {
        setOpen(false);
    }, [pathname]);

    if (!isMounted) {
        return null;
    }

    return (
        <Sheet open={open} onOpenChange={setOpen}>
            <SheetTrigger asChild>
                <Button variant="ghost" size="icon" className="md:hidden">
                    <Menu className="h-6 w-6 text-foreground" />
                </Button>
            </SheetTrigger>
            <SheetContent side="left" className="p-0 bg-transparent border-none w-72">
                <Sidebar user={user} userRole={userRole} userAvatar={userAvatar} userName={userName} />
            </SheetContent>
        </Sheet>
    );
};

'use client'

import { useState, useEffect } from 'react'
import { Bell } from 'lucide-react'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Button } from '@/components/ui/button'
import { createClient } from '@/lib/supabase/client'
import { cn } from '@/lib/utils'
import Link from 'next/link'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'

interface Notification {
    id: string
    title: string
    message: string
    link: string | null
    read: boolean
    created_at: string
}

export function NotificationsDropdown({ userId }: { userId: string }) {
    const [notifications, setNotifications] = useState<Notification[]>([])
    const [unreadCount, setUnreadCount] = useState(0)
    const [isOpen, setIsOpen] = useState(false)
    const supabase = createClient()

    const fetchNotifications = async () => {
        const { data, error } = await supabase
            .from('notifications')
            .select('*')
            .eq('user_id', userId)
            .order('created_at', { ascending: false })
            .limit(10)

        if (!error && data) {
            setNotifications(data)
            setUnreadCount(data.filter(n => !n.read).length)
        }
    }

    // Real-time subscription
    useEffect(() => {
        fetchNotifications()

        const channel = supabase
            .channel('notifications_changes')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'notifications',
                    filter: `user_id=eq.${userId}`
                },
                (payload) => {
                    setNotifications(prev => [payload.new as Notification, ...prev])
                    setUnreadCount(prev => prev + 1)
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [userId])

    const markAsRead = async (id: string) => {
        await supabase
            .from('notifications')
            .update({ read: true })
            .eq('id', id)

        setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n))
        setUnreadCount(prev => Math.max(0, prev - 1))
    }

    const markAllAsRead = async () => {
        await supabase
            .from('notifications')
            .update({ read: true })
            .eq('user_id', userId)
            .eq('read', false)

        setNotifications(prev => prev.map(n => ({ ...n, read: true })))
        setUnreadCount(0)
    }

    return (
        <DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
            <DropdownMenuTrigger asChild>
                <Button variant="ghost" size="icon" className="relative group hover:bg-white/5 rounded-xl transition-all">
                    <Bell className="h-5 w-5 text-slate-400 group-hover:text-cyan-400 transition-colors" />
                    {unreadCount > 0 && (
                        <span className="absolute top-2 right-2 h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-slate-950 animate-pulse" />
                    )}
                </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-[320px] bg-slate-950/90 backdrop-blur-xl border border-slate-800/50 rounded-2xl p-0 shadow-2xl">
                <div className="flex items-center justify-between p-4 border-b border-border/50">
                    <h4 className="text-sm font-black uppercase tracking-widest text-foreground">Notificações</h4>
                    {unreadCount > 0 && (
                        <button
                            onClick={markAllAsRead}
                            className="text-[10px] uppercase font-bold text-cyan-500 hover:text-cyan-400 transition-colors"
                        >
                            Marcar lidas
                        </button>
                    )}
                </div>

                <div className="max-h-[400px] overflow-y-auto">
                    {notifications.length === 0 ? (
                        <div className="p-8 text-center text-slate-500 text-sm italic">
                            Nenhuma notificação recente
                        </div>
                    ) : (
                        notifications.map((notification) => (
                            <DropdownMenuItem
                                key={notification.id}
                                className={cn(
                                    "p-4 flex flex-col gap-1 cursor-pointer border-b border-border/20 last:border-0 hover:bg-white/5 focus:bg-white/5",
                                    !notification.read && "bg-cyan-950/20"
                                )}
                                onClick={() => {
                                    if (!notification.read) markAsRead(notification.id)
                                }}
                            >
                                <div className="flex justify-between w-full">
                                    <span className={cn("text-xs font-bold", !notification.read ? "text-cyan-400" : "text-slate-300")}>
                                        {notification.title}
                                    </span>
                                    <span className="text-[9px] text-slate-500 uppercase tracking-widest">
                                        {formatDistanceToNow(new Date(notification.created_at), { addSuffix: true, locale: ptBR })}
                                    </span>
                                </div>
                                <p className="text-xs text-slate-400 leading-relaxed line-clamp-2">
                                    {notification.message}
                                </p>
                                {notification.link && (
                                    <Link
                                        href={notification.link}
                                        className="mt-2 text-[10px] font-black uppercase tracking-widest text-cyan-500 hover:text-cyan-400 flex items-center gap-1"
                                    >
                                        Ver detalhes →
                                    </Link>
                                )}
                            </DropdownMenuItem>
                        ))
                    )}
                </div>
            </DropdownMenuContent>
        </DropdownMenu>
    )
}

'use client'

import React, { createContext, useContext, useState, useEffect } from 'react'
import { dictionaries, Locale } from '@/lib/i18n/dictionaries'

type Dictionary = typeof dictionaries['pt']

interface LanguageContextType {
    language: Locale
    setLanguage: (lang: Locale) => void
    t: (key: string) => string
    dictionary: Dictionary
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined)

export function LanguageProvider({ children }: { children: React.ReactNode }) {
    const [language, setLanguageState] = useState<Locale>('pt')

    useEffect(() => {
        // Try to load from localStorage
        const saved = localStorage.getItem('app_language') as Locale
        if (saved && ['pt', 'en', 'es'].includes(saved)) {
            setLanguageState(saved)
        }
    }, [])

    const setLanguage = (lang: Locale) => {
        setLanguageState(lang)
        localStorage.setItem('app_language', lang)
    }

    // Helper to get nested translation safely
    // Key format: 'category.key' e.g. 'sidebar.dashboard'
    const t = (key: string): string => {
        const keys = key.split('.')
        let current: Record<string, unknown> | string = dictionaries[language] as Record<string, unknown>

        for (const k of keys) {
            if (typeof current === 'string' || current[k] === undefined) {
                console.warn(`Missing translation for key: ${key} in language: ${language}`)
                return key // Fallback to key name
            }
            current = current[k] as Record<string, unknown> | string
        }

        return typeof current === 'string' ? current : key
    }

    return (
        <LanguageContext.Provider value={{ language, setLanguage, t, dictionary: dictionaries[language] as Dictionary }}>
            {children}
        </LanguageContext.Provider>
    )
}

export function useLanguage() {
    const context = useContext(LanguageContext)
    if (context === undefined) {
        throw new Error('useLanguage must be used within a LanguageProvider')
    }
    return context
}

'use client'

import { useEffect, useRef, useState } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Mic, MicOff, Video, VideoOff, Settings, Sparkles, User, Monitor, Headphones, ChevronDown, Check, Volume2, Ghost, EyeOff } from 'lucide-react'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { cn } from '@/lib/utils'
import { useMediaStream } from '@/hooks/use-media-stream'

interface PreCallLobbyProps {
    userName: string
    userRole: string
    isGuest: boolean
    onJoin: (config: {
        micOn: boolean
        cameraOn: boolean
        isGhost: boolean
        name: string
        audioDeviceId: string
        videoDeviceId: string
        stream?: MediaStream
    }) => void
}

export function PreCallLobby({ userName, userRole, isGuest, onJoin }: PreCallLobbyProps) {
    const [name, setName] = useState(userName || '')
    const [micOn, setMicOn] = useState(true)
    const [cameraOn, setCameraOn] = useState(true)
    const [isGhost, setIsGhost] = useState(false)
    const [audioDevices, setAudioDevices] = useState<MediaDeviceInfo[]>([])
    const [videoDevices, setVideoDevices] = useState<MediaDeviceInfo[]>([])
    const [selectedAudioId, setSelectedAudioId] = useState<string>('')
    const [selectedVideoId, setSelectedVideoId] = useState<string>('')
    const isJoiningRef = useRef(false)

    // Volume Meter State
    const [volumeLevel, setVolumeLevel] = useState(0)
    const requestRef = useRef<number>()
    const analyserRef = useRef<AnalyserNode | null>(null)

    // Use our refactored hook
    const { stream, error, toggleMic, toggleCamera, switchDevice } = useMediaStream({
        micOn,
        cameraOn,
        audioDeviceId: selectedAudioId,
        videoDeviceId: selectedVideoId
    }, true) // isJoined = true immediately for preview

    // Audio Visualization Loop
    useEffect(() => {
        if (!stream || !micOn) {
            setVolumeLevel(0)
            return
        }

        try {
            const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)()
            const analyser = audioContext.createAnalyser()
            const source = audioContext.createMediaStreamSource(stream)
            source.connect(analyser)
            analyser.fftSize = 256
            analyserRef.current = analyser

            const bufferLength = analyser.frequencyBinCount
            const dataArray = new Uint8Array(bufferLength)

            const updateVolume = () => {
                analyser.getByteFrequencyData(dataArray)
                const sum = dataArray.reduce((src, a) => src + a, 0)
                const avg = sum / bufferLength
                // Normalize roughly to 0-100, assuming max typical volume
                setVolumeLevel(Math.min(100, avg * 2))
                requestRef.current = requestAnimationFrame(updateVolume)
            }
            updateVolume()

            return () => {
                if (requestRef.current) cancelAnimationFrame(requestRef.current)
                if (audioContext.state !== 'closed') audioContext.close()
            }
        } catch (e) {
            console.error("Audio Context Error", e)
        }
    }, [stream, micOn])


    const videoRef = useRef<HTMLVideoElement>(null)

    // Enumerate Devices
    useEffect(() => {
        async function getDevices() {
            try {
                const devices = await navigator.mediaDevices.enumerateDevices()
                setAudioDevices(devices.filter(d => d.kind === 'audioinput'))
                setVideoDevices(devices.filter(d => d.kind === 'videoinput'))

                // Set initial selection if empty (use defaults or first found)
                if (!selectedAudioId) {
                    const audio = devices.find(d => d.kind === 'audioinput')
                    if (audio) setSelectedAudioId(audio.deviceId)
                }
                if (!selectedVideoId) {
                    const video = devices.find(d => d.kind === 'videoinput')
                    if (video) setSelectedVideoId(video.deviceId)
                }
            } catch (e) {
                console.error("Error enumerating devices", e)
            }
        }
        getDevices()
        navigator.mediaDevices.addEventListener('devicechange', getDevices)
        return () => navigator.mediaDevices.removeEventListener('devicechange', getDevices)
    }, [])

    // Ensure video element gets the stream
    useEffect(() => {
        if (videoRef.current && stream) {
            videoRef.current.srcObject = stream
        }
    }, [stream])

    const handleJoin = () => {
        if (!name.trim()) return
        isJoiningRef.current = true
        onJoin({
            micOn: isGhost ? false : micOn,
            cameraOn: isGhost ? false : cameraOn,
            isGhost,
            name,
            audioDeviceId: selectedAudioId || 'default',
            videoDeviceId: selectedVideoId || 'default',
            // IMPORTANT: Pass the stream?
            // Actually, if we pass the stream, we risk track ownership issues.
            // But useMediaStream handles cleanup via 'isJoined'.
            // If the parent component (RoomPage) mounts <VideoRoom> which calls useWebRTC...
            // useWebRTC will create a NEW stream based on deviceIds.
            // So we can stop this stream here (by unmounting PreCallLobby).
        })
    }

    return (
        <div className="min-h-screen w-full flex flex-col items-center justify-center bg-[#020817] relative overflow-hidden p-6 text-foreground">
            {/* Background Effects */}
            <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
                <div className="absolute top-[-20%] right-[-10%] w-[800px] h-[800px] bg-purple-600/20 rounded-full blur-[120px]" />
                <div className="absolute bottom-[-20%] left-[-10%] w-[600px] h-[600px] bg-blue-600/10 rounded-full blur-[100px]" />
            </div>

            <div className="max-w-5xl w-full grid md:grid-cols-2 gap-12 z-10">
                {/* Left Column: Preview */}
                <div className="flex flex-col gap-6 animate-in slide-in-from-left-8 duration-700">
                    <div className="relative aspect-video rounded-3xl overflow-hidden bg-slate-900 border border-slate-800 shadow-2xl group">
                        {stream && cameraOn ? (
                            <video
                                ref={videoRef}
                                autoPlay
                                muted
                                playsInline
                                className="w-full h-full object-cover transform scale-x-[-1]"
                            />
                        ) : (
                            <div className="w-full h-full flex flex-col items-center justify-center text-slate-500 gap-4 bg-slate-900/50">
                                <div className="p-4 rounded-full bg-slate-800/50">
                                    <VideoOff className="h-12 w-12 opacity-50" />
                                </div>
                                <p>Câmera desativada</p>
                            </div>
                        )}

                        {error && (
                            <div className="absolute inset-0 flex items-center justify-center bg-black/80 text-red-400 p-4 text-center z-20">
                                <p>Erro ao acessar mídia: {error}</p>
                            </div>
                        )}

                        {/* Overlay Controls */}
                        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-black/60 backdrop-blur-xl p-2 rounded-2xl border border-white/10 transition-opacity opacity-100 md:opacity-0 md:group-hover:opacity-100">

                            {/* Mic Split Button */}
                            <div className="flex items-center bg-zinc-800/80 rounded-xl overflow-hidden border border-white/10">
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className={cn(
                                        "h-12 w-12 rounded-none hover:bg-white/10 transition-all",
                                        micOn ? "text-white" : "text-red-500 bg-red-500/10"
                                    )}
                                    onClick={() => setMicOn(!micOn)}
                                >
                                    {micOn ? <Mic className="h-5 w-5" /> : <MicOff className="h-5 w-5" />}
                                </Button>
                                <div className="w-px h-6 bg-white/10" />
                                <DropdownMenu>
                                    <DropdownMenuTrigger asChild>
                                        <Button variant="ghost" className="h-12 w-8 px-0 rounded-none hover:bg-white/10 text-zinc-400 hover:text-white">
                                            <ChevronDown className="h-4 w-4" />
                                        </Button>
                                    </DropdownMenuTrigger>
                                    <DropdownMenuContent side="top" align="center" className="w-64 bg-zinc-900 border-zinc-800 text-zinc-200">
                                        <DropdownMenuLabel>Microfone</DropdownMenuLabel>
                                        <DropdownMenuSeparator className="bg-zinc-800" />
                                        {audioDevices.map(device => (
                                            <DropdownMenuItem
                                                key={device.deviceId}
                                                onClick={() => setSelectedAudioId(device.deviceId)}
                                                className="cursor-pointer focus:bg-zinc-800 focus:text-white flex justify-between"
                                            >
                                                <span className="truncate max-w-[180px]">{device.label || `Mic ${device.deviceId.slice(0, 4)}`}</span>
                                                {selectedAudioId === device.deviceId && <Check className="h-4 w-4 text-purple-500 ml-2" />}
                                            </DropdownMenuItem>
                                        ))}
                                    </DropdownMenuContent>
                                </DropdownMenu>
                            </div>

                            {/* Camera Split Button */}
                            <div className="flex items-center bg-zinc-800/80 rounded-xl overflow-hidden border border-white/10">
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className={cn(
                                        "h-12 w-12 rounded-none hover:bg-white/10 transition-all",
                                        cameraOn ? "text-white" : "text-red-500 bg-red-500/10"
                                    )}
                                    onClick={() => setCameraOn(!cameraOn)}
                                >
                                    {cameraOn ? <Video className="h-5 w-5" /> : <VideoOff className="h-5 w-5" />}
                                </Button>
                                <div className="w-px h-6 bg-white/10" />
                                <DropdownMenu>
                                    <DropdownMenuTrigger asChild>
                                        <Button variant="ghost" className="h-12 w-8 px-0 rounded-none hover:bg-white/10 text-zinc-400 hover:text-white">
                                            <ChevronDown className="h-4 w-4" />
                                        </Button>
                                    </DropdownMenuTrigger>
                                    <DropdownMenuContent side="top" align="center" className="w-64 bg-zinc-900 border-zinc-800 text-zinc-200">
                                        <DropdownMenuLabel>Câmera</DropdownMenuLabel>
                                        <DropdownMenuSeparator className="bg-zinc-800" />
                                        {videoDevices.map(device => (
                                            <DropdownMenuItem
                                                key={device.deviceId}
                                                onClick={() => setSelectedVideoId(device.deviceId)}
                                                className="cursor-pointer focus:bg-zinc-800 focus:text-white flex justify-between"
                                            >
                                                <span className="truncate max-w-[180px]">{device.label || `Cam ${device.deviceId.slice(0, 4)}`}</span>
                                                {selectedVideoId === device.deviceId && <Check className="h-4 w-4 text-purple-500 ml-2" />}
                                            </DropdownMenuItem>
                                        ))}
                                    </DropdownMenuContent>
                                </DropdownMenu>
                            </div>

                        </div>

                        {/* Status Badge */}
                        <div className="absolute top-6 left-6 px-3 py-1 bg-black/60 backdrop-blur-md rounded-lg text-xs font-bold text-white border border-white/10 flex items-center gap-2">
                            <div className={cn("w-2 h-2 rounded-full", stream ? "bg-green-500 animate-pulse" : "bg-red-500")} />
                            {stream ? "Pronto para entrar" : "Verificando dispositivos..."}
                        </div>

                        {/* Audio Meter (Visual Feedback) */}
                        {micOn && (
                            <div className="absolute bottom-6 right-6 h-12 w-1.5 bg-black/40 rounded-full overflow-hidden border border-white/10">
                                <div
                                    className="w-full bg-green-500 transition-[height] duration-75 ease-out bottom-0 absolute rounded-full"
                                    style={{ height: `${volumeLevel}%` }}
                                />
                            </div>
                        )}
                    </div>

                    {/* Audio Check Text */}
                    <div className="flex items-center gap-2 text-slate-400 text-sm px-2">
                        <Volume2 className={cn("h-4 w-4", volumeLevel > 10 ? "text-green-500" : "text-slate-600")} />
                        <span>
                            {volumeLevel > 0 ? "Áudio detectado!" : "Fale para testar o microfone..."}
                        </span>
                    </div>
                </div>

                {/* Right Column: Controls */}
                <div className="flex flex-col justify-center gap-8 animate-in slide-in-from-right-8 duration-700 delay-100">
                    <div>
                        <h1 className="text-4xl md:text-5xl font-black tracking-tighter text-white mb-4">
                            Tudo pronto?
                        </h1>
                        <p className="text-slate-400 text-lg">
                            Configure seu áudio e vídeo antes de entrar na reunião.
                        </p>
                    </div>

                    <div className="space-y-6 bg-slate-900/40 p-8 rounded-3xl border border-white/5 backdrop-blur-sm">

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Seu Nome</label>
                            <div className="relative">
                                <User className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-500" />
                                <Input
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    className="pl-12 h-14 bg-slate-950/50 border-slate-800 text-lg focus:ring-purple-500/50 rounded-xl text-white placeholder:text-slate-600"
                                    placeholder="Como quer ser chamado?"
                                />
                            </div>
                        </div>

                        {(!stream && !error) ? (
                            <div className="w-full h-16 flex items-center justify-center gap-3 bg-slate-800/20 rounded-2xl border border-white/5 text-slate-500 font-medium">
                                <div className="h-4 w-4 border-2 border-[#06b6d4] border-t-transparent rounded-full animate-spin" />
                                <span>Iniciando dispositivos...</span>
                            </div>
                        ) : error ? (
                            <div className="w-full p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-sm text-center">
                                <p>Não foi possível acessar sua câmera/microfone.</p>
                                <p className="text-xs mt-1 opacity-70">Verifique as permissões do navegador.</p>
                            </div>
                        ) : (
                            <Button
                                onClick={handleJoin}
                                disabled={!name.trim() || isJoiningRef.current}
                                className="w-full h-16 text-lg font-bold rounded-2xl bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 transition-all shadow-[0_0_40px_rgba(79,70,229,0.3)] hover:shadow-[0_0_60px_rgba(79,70,229,0.4)]"
                            >
                                {isJoiningRef.current ? (
                                    <div className="flex items-center gap-2">
                                        <div className="h-4 w-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                                        <span>Entrando...</span>
                                    </div>
                                ) : (
                                    <>Entrar na Sala <Sparkles className="ml-2 h-5 w-5" /></>
                                )}
                            </Button>
                        )}

                        {!isGuest && (
                            <div className="flex flex-col gap-4">
                                {(userRole === 'admin' || userRole === 'MASTER') && (
                                    <div
                                        className={cn(
                                            "flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group",
                                            isGhost
                                                ? "bg-purple-500/20 border-purple-500/50 shadow-[0_0_20px_rgba(168,85,247,0.2)]"
                                                : "bg-slate-950/30 border-slate-800 hover:border-slate-700"
                                        )}
                                        onClick={() => {
                                            setIsGhost(!isGhost)
                                            if (!isGhost) {
                                                setMicOn(false)
                                                setCameraOn(false)
                                            }
                                        }}
                                    >
                                        <div className="flex items-center gap-3">
                                            <div className={cn(
                                                "p-2 rounded-lg transition-colors",
                                                isGhost ? "bg-purple-500 text-white" : "bg-slate-800 text-slate-400 group-hover:text-slate-300"
                                            )}>
                                                <Ghost className="h-5 w-5" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-sm font-bold text-white">Modo Fantasma</span>
                                                <span className="text-[10px] text-slate-500 uppercase font-black">Auditoria Invisível</span>
                                            </div>
                                        </div>
                                        <div className={cn(
                                            "w-12 h-6 rounded-full relative transition-colors duration-300",
                                            isGhost ? "bg-purple-500" : "bg-slate-800"
                                        )}>
                                            <div className={cn(
                                                "absolute top-1 w-4 h-4 rounded-full bg-white transition-all duration-300",
                                                isGhost ? "left-7" : "left-1"
                                            )} />
                                        </div>
                                    </div>
                                )}

                                <div className="text-center">
                                    <p className="text-xs text-slate-500">
                                        Conectado como <span className="text-slate-300 font-medium uppercase text-[10px] tracking-widest">{userName}</span>
                                        {(userRole === 'admin' || userRole === 'MASTER') && <span className="ml-2 px-1.5 py-0.5 rounded bg-purple-500/20 text-purple-400 border border-purple-500/30 text-[9px] font-bold">ADMIN</span>}
                                    </p>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    )
}

