import { useState, useEffect, useRef } from 'react'
import { createClient } from '@/lib/supabase/client'

export interface Message {
    id: string
    sender: string
    senderName?: string
    text: string
    timestamp: number
    role: string
    recipientId?: string // Who this message is for (optional)
}

function playNotificationSound() {
    try {
        const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
        if (!AudioContext) return;

        const ctx = new AudioContext();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.connect(gain);
        gain.connect(ctx.destination);

        osc.type = 'sine';
        osc.frequency.setValueAtTime(500, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(1000, ctx.currentTime + 0.1);

        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1);

        osc.start();
        osc.stop(ctx.currentTime + 0.1);
    } catch (e) {
        console.error("Audio play failed", e);
    }
}

export function useChat(roomId: string, userId: string, userRole: string, userName: string) {
    const [messages, setMessages] = useState<Message[]>([])
    const [unreadCount, setUnreadCount] = useState(0)
    const [isActive, setIsActive] = useState(false)
    const isActiveRef = useRef(false)
    const supabase = createClient()
    const channelRef = useRef<any>(null)
    const seenMessagesRef = useRef<Set<string>>(new Set())

    // Helper to parse message content
    const parseContent = (content: string): { text: string, recipientId?: string } => {
        try {
            // Check if it looks like our JSON format unique signature
            if (content.startsWith('{"v":1')) {
                const parsed = JSON.parse(content)
                return { text: parsed.text, recipientId: parsed.recipientId }
            }
        } catch (e) {
            // Ignore parse error, treat as plain text
        }
        return { text: content }
    }

    // Keep ref in sync
    useEffect(() => {
        isActiveRef.current = isActive
    }, [isActive])

    useEffect(() => {
        if (!roomId) return

        // 1. Fetch History
        const fetchHistory = async () => {
            const { data, error } = await supabase
                .from('messages')
                .select('*')
                .eq('room_id', roomId)
                .order('created_at', { ascending: true })

            if (data) {
                const mapped: Message[] = data.map((d: any) => {
                    const { text, recipientId } = parseContent(d.content)

                    const msg = {
                        id: d.id,
                        sender: d.sender_id,
                        senderName: d.sender_name,
                        text,
                        timestamp: new Date(d.created_at).getTime(),
                        role: d.role,
                        recipientId // New field
                    }
                    seenMessagesRef.current.add(msg.id)
                    // Also add a fuzzy key for history
                    seenMessagesRef.current.add(`${msg.sender}:${msg.text}:${Math.floor(msg.timestamp / 2000)}`)
                    return msg
                }).filter((msg: any) => {
                    // Filter history: Show if Public OR (Private AND (I am sender OR I am recipient))
                    if (!msg.recipientId) return true
                    return msg.sender === userId || msg.recipientId === userId
                })
                setMessages(mapped)
            }
        }
        fetchHistory()

        // 2. Subscribe to NEW additions (Realtime & Broadcast Fallback)
        const channel = supabase.channel(`room-chat:${roomId}`)
        channelRef.current = channel

        const handleNewMessage = (msg: Message, fromPostgres = false) => {
            const fuzzyKey = `${msg.sender}:${msg.text}:${Math.floor(msg.timestamp / 2000)}`

            // Deduplicate by exact ID OR fuzzy key (sender+text+time window)
            if (seenMessagesRef.current.has(msg.id) || seenMessagesRef.current.has(fuzzyKey)) {
                return
            }

            // FILTER: If private, strict check
            if (msg.recipientId && msg.recipientId !== userId && msg.sender !== userId) {
                return
            }

            seenMessagesRef.current.add(msg.id)
            seenMessagesRef.current.add(fuzzyKey)

            setMessages(prev => [...prev, msg])

            // Notify if not active and NOT my own message
            if (msg.sender !== userId && !isActiveRef.current) {
                setUnreadCount(prev => prev + 1)
                playNotificationSound()
            }
        }

        channel
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'messages',
                    filter: `room_id=eq.${roomId}`
                },
                (payload) => {
                    const newMsg = payload.new as any
                    if (!newMsg) return

                    const { text, recipientId } = parseContent(newMsg.content)

                    const msg: Message = {
                        id: newMsg.id,
                        sender: newMsg.sender_id,
                        senderName: newMsg.sender_name,
                        text,
                        timestamp: new Date(newMsg.created_at).getTime(),
                        role: newMsg.role,
                        recipientId
                    }
                    handleNewMessage(msg, true)
                }
            )
            .on('broadcast', { event: 'chat-message' }, (payload) => {
                const msg = payload.payload as Message
                if (msg.sender === userId) return // Ignore own
                handleNewMessage(msg)
            })
            .subscribe()

        return () => {
            channel.unsubscribe()
        }
    }, [roomId, userId])

    const sendMessage = async (text: string, recipientId?: string) => {
        if (!text.trim()) return

        const msgId = crypto.randomUUID?.() || Math.random().toString(36).substring(2, 15)
        const timestamp = Date.now()

        const msg: Message = {
            id: msgId,
            sender: userId,
            senderName: userName,
            text,
            timestamp,
            role: userRole,
            recipientId
        }

        // Add to seen BEFORE optimistic update to avoid duplicates if broadcast arrives too fast
        const fuzzyKey = `${msg.sender}:${msg.text}:${Math.floor(msg.timestamp / 2000)}`
        seenMessagesRef.current.add(msg.id)
        seenMessagesRef.current.add(fuzzyKey)

        // 1. Optimistic local update
        setMessages(prev => [...prev, msg])

        // 2. Broadcast for real-time (Ensures Guest delivery)
        channelRef.current?.send({
            type: 'broadcast',
            event: 'chat-message',
            payload: msg
        })

        // 3. Persistent storage
        try {
            // If recipientId is present, we wrap content in JSON
            let contentToSave = text
            if (recipientId) {
                contentToSave = JSON.stringify({ v: 1, text, recipientId })
            }

            await supabase.from('messages').insert({
                id: msgId,
                room_id: roomId,
                sender_id: userId,
                sender_name: userName,
                content: contentToSave,
                role: userRole
            })
        } catch (e) {
            console.error("Chat Insert exception:", e)
        }
    }

    const markAsRead = () => {
        setUnreadCount(0)
    }

    return {
        messages,
        sendMessage,
        unreadCount,
        markAsRead,
        setIsActive
    }
}

import { useState, useEffect, useCallback, RefObject } from 'react'

interface LayoutParams {
    width: number
    height: number
    cols: number
    rows: number
    count: number
}

export function useGalleryLayout(containerRef: RefObject<HTMLElement | null>, participantCount: number) {
    const [layout, setLayout] = useState<LayoutParams>({ width: 320, height: 180, cols: 1, rows: 1, count: 0 })

    const calculateLayout = useCallback(() => {
        if (!containerRef.current || participantCount === 0) return

        const { clientWidth: containerWidth, clientHeight: containerHeight } = containerRef.current
        const ratio = 16 / 9

        let bestWidth = 0
        let bestHeight = 0
        let bestCols = 1
        let bestRows = 1

        // Brute force search for best grid configuration
        for (let cols = 1; cols <= participantCount; cols++) {
            const rows = Math.ceil(participantCount / cols)

            // Calculate max possible width/height for this configuration
            let w = containerWidth / cols
            let h = w / ratio

            // If height exceeds space, scale down based on rows
            if (h * rows > containerHeight) {
                h = containerHeight / rows
                w = h * ratio
            }

            // Area optimization
            if (w * h > bestWidth * bestHeight) {
                bestWidth = w
                bestHeight = h
                bestCols = cols
                bestRows = rows
            }
        }

        // Apply scaling constraints (V11.3: Adjusted for tablets)
        const isSmallScreen = containerWidth < 768
        const padding = isSmallScreen ? 4 : 12

        setLayout({
            width: Math.floor(bestWidth - padding),
            height: Math.floor(bestHeight - padding),
            cols: bestCols,
            rows: bestRows,
            count: participantCount
        })
    }, [participantCount, containerRef])

    useEffect(() => {
        calculateLayout()
        const resizeObserver = new ResizeObserver(() => calculateLayout())
        if (containerRef.current) resizeObserver.observe(containerRef.current)
        return () => resizeObserver.disconnect()
    }, [calculateLayout, containerRef])

    return layout
}

import { useState, useRef, useEffect, useCallback } from 'react'

export interface MediaStreamConfig {
    micOn?: boolean
    cameraOn?: boolean
    audioDeviceId?: string
    videoDeviceId?: string
    stream?: MediaStream
}

export function useMediaStream(config: MediaStreamConfig = {}, isJoined: boolean = false) {
    const [stream, setStream] = useState<MediaStream | null>(null)
    const [error, setError] = useState<string | null>(null)

    // Refs to keep track of current tracks to avoid stale closures
    const currentAudioTrackRef = useRef<MediaStreamTrack | null>(null)
    const currentVideoTrackRef = useRef<MediaStreamTrack | null>(null)

    // Initialize stream
    useEffect(() => {
        let mounted = true
        let activeStream: MediaStream | null = null

        const init = async () => {
            if (!isJoined) return

            try {
                if (config.stream) {
                    activeStream = config.stream
                } else {
                    const constraints = {
                        audio: config.micOn !== false ? {
                            deviceId: config.audioDeviceId ? { exact: config.audioDeviceId } : undefined,
                            echoCancellation: true,
                            noiseSuppression: true,
                            autoGainControl: true
                        } : false,
                        video: config.cameraOn !== false
                            ? (config.videoDeviceId
                                ? { deviceId: { exact: config.videoDeviceId } }
                                : { facingMode: 'user' })
                            : false
                    }
                    console.log('--- Requesting UserMedia with constraints:', constraints)
                    activeStream = await navigator.mediaDevices.getUserMedia(constraints)
                }

                if (!mounted) {
                    activeStream.getTracks().forEach(t => t.stop())
                    return
                }

                // Initial mute state
                if (config.micOn === false) activeStream.getAudioTracks().forEach(t => t.enabled = false)
                if (config.cameraOn === false) activeStream.getVideoTracks().forEach(t => t.enabled = false)

                currentAudioTrackRef.current = activeStream.getAudioTracks()[0] || null
                currentVideoTrackRef.current = activeStream.getVideoTracks()[0] || null

                setStream(activeStream)
                setError(null)
            } catch (err: any) {
                if (mounted) setError(err.message)
            }
        }

        init()

        return () => {
            mounted = false
            // Only stop tracks if we created the stream (not passed in config)
            if (activeStream && !config.stream) {
                activeStream.getTracks().forEach(t => t.stop())
            }
        }
    }, [isJoined, config.audioDeviceId, config.videoDeviceId, config.stream])

    const toggleMic = useCallback((enabled: boolean) => {
        if (stream) {
            stream.getAudioTracks().forEach(t => t.enabled = enabled)
        }
    }, [stream])

    const toggleCamera = useCallback((enabled: boolean) => {
        if (stream) {
            stream.getVideoTracks().forEach(t => t.enabled = enabled)
        }
    }, [stream])

    const switchDevice = useCallback(async (kind: 'audio' | 'video', deviceId: string) => {
        if (!stream) return

        try {
            const constraints = kind === 'audio'
                ? { audio: { deviceId: { exact: deviceId } } }
                : { video: { deviceId: { exact: deviceId } } }

            const newStream = await navigator.mediaDevices.getUserMedia(constraints)
            const newTrack = kind === 'audio' ? newStream.getAudioTracks()[0] : newStream.getVideoTracks()[0]

            const oldTrack = kind === 'audio' ? currentAudioTrackRef.current : currentVideoTrackRef.current

            if (oldTrack) {
                stream.removeTrack(oldTrack)
                oldTrack.stop()
            }

            stream.addTrack(newTrack)

            if (kind === 'audio') currentAudioTrackRef.current = newTrack
            else currentVideoTrackRef.current = newTrack

            // Notify caller that track changed (useful for renegotiation if needed)
            return newTrack
        } catch (err) {
            console.error(`Failed to switch ${kind} device:`, err)
            throw err
        }
    }, [stream])

    return {
        stream,
        error,
        toggleMic,
        toggleCamera,
        switchDevice
    }
}

import { useEffect, useRef, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { RealtimeChannel } from '@supabase/supabase-js'

export interface SignalingEvents {
    onSignal: (payload: any) => void
    onShareStarted: (payload: any) => void
    onShareEnded: (payload: any) => void
    onHostPromoted: (payload: any) => void
    onReaction: (payload: any) => void
    onRoomEvent: (payload: any) => void
    onPresenceSync: (users: string[], state: any) => void
}

export function useSignaling(roomId: string, userId: string, metadata: any, events: SignalingEvents, enabled: boolean = true) {
    const [channel, setChannel] = useState<RealtimeChannel | null>(null)
    const channelRef = useRef<RealtimeChannel | null>(null)
    const supabase = createClient()
    const metadataRef = useRef(metadata)

    const eventsRef = useRef(events)

    useEffect(() => {
        eventsRef.current = events
    }, [events])

    // Keep metadata ref up to date
    useEffect(() => {
        metadataRef.current = metadata
        if (channelRef.current) {
            // Debounce or check for diff could be added here
            // channelRef.current.track(metadata)
        }
    }, [metadata])

    const [connectionState, setConnectionState] = useState<string>('disconnected')

    useEffect(() => {
        // Prevent joining if no userId or if not enabled
        if (!userId || !roomId || !enabled) return

        console.log("Connecting to Signaling Channel:", roomId)
        const newChannel = supabase.channel(`room:${roomId}`, { config: { presence: { key: userId } } })
        channelRef.current = newChannel
        setChannel(newChannel)
        setConnectionState('connecting')

        newChannel
            .on('broadcast', { event: 'signal' }, (e) => eventsRef.current.onSignal(e.payload))
            .on('broadcast', { event: 'share-started' }, (e) => eventsRef.current.onShareStarted(e.payload))
            .on('broadcast', { event: 'share-ended' }, (e) => eventsRef.current.onShareEnded(e.payload))
            .on('broadcast', { event: 'host-promoted' }, (e) => eventsRef.current.onHostPromoted(e.payload))
            .on('broadcast', { event: 'reaction' }, (e) => eventsRef.current.onReaction(e.payload))
            // Database Events (Room Actions)
            .on(
                'postgres_changes',
                { event: 'INSERT', schema: 'public', table: 'room_events', filter: `meeting_id=eq.${roomId}` },
                (payload) => eventsRef.current.onRoomEvent(payload.new)
            )
            .on('presence', { event: 'sync' }, () => {
                const state = newChannel.presenceState()
                const users = Object.keys(state)
                eventsRef.current.onPresenceSync(users, state)
            })
            .subscribe(async (status) => {
                setConnectionState(status)
                if (status === 'SUBSCRIBED') {
                    await newChannel.track(metadataRef.current)
                }
            })

        return () => {
            console.log("Disconnecting Signaling Channel")
            newChannel.unsubscribe()
            setConnectionState('disconnected')
        }
    }, [roomId, userId, enabled]) // Events ref is stable, no need to add

    const sendSignal = useCallback((payload: any) => {
        channelRef.current?.send({ type: 'broadcast', event: 'signal', payload })
    }, [])

    const sendReaction = useCallback((emoji: string) => {
        channelRef.current?.send({ type: 'broadcast', event: 'reaction', payload: { emoji, sender: userId } })
    }, [userId])

    const broadcastEvent = useCallback((event: string, payload: any) => {
        channelRef.current?.send({ type: 'broadcast', event, payload })
    }, [])

    const trackMetadata = useCallback(async (newMetadata: any) => {
        if (channelRef.current) {
            await channelRef.current.track(newMetadata)
        }
    }, [])

    return {
        channel,
        connectionState,
        sendSignal,
        sendReaction,
        broadcastEvent,
        trackMetadata
    }
}

import { useEffect, useState, useRef, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import '@/lib/polyfills'
import { RealtimeChannel } from '@supabase/supabase-js'
import {
    Room,
    RoomEvent,
    RemoteParticipant,
    RemoteTrack,
    RemoteTrackPublication,
    Participant,
    Track,
    VideoQuality,
    LocalTrackPublication
} from 'livekit-client'
import { useMediaStream } from './use-media-stream'
import { useSignaling } from './use-signaling'

interface PeerData {
    userId: string
    stream?: MediaStream
    screenStream?: MediaStream
    role: string
    language?: string
    micOn?: boolean
    cameraOn?: boolean
    isSpeaking?: boolean
    isGhost?: boolean
    handRaised?: boolean
    name?: string
    isPresentation?: boolean
    isHost?: boolean
    connectionState?: 'connecting' | 'connected' | 'failed' | 'disconnected'
    audioBlocked?: boolean
    joinedAt?: number
}

interface UserMetadata {
    name: string
    role: string
    micOn: boolean
    cameraOn: boolean
    handRaised: boolean
    language: string
    audioBlocked: boolean
    isHost: boolean
    isGhost: boolean
}

export function useWebRTC(
    roomId: string,
    userId: string,
    userRole: string = 'participant',
    initialConfig: { micOn?: boolean, cameraOn?: boolean, audioDeviceId?: string, videoDeviceId?: string, stream?: MediaStream } = {},
    isJoined: boolean = false,
    userName: string = 'Participante',
    liveKitToken?: string,
    isGhostMode: boolean = false,
    initialHostId?: string
) {
    const sessionUserId = userId // O userId já vem com o sufixo da RoomPage

    // --- Refactored: useMediaStream ---
    const { stream: localStream, error: mediaError, toggleMic: toggleMicStream, toggleCamera: toggleCameraStream, switchDevice } = useMediaStream({
        micOn: initialConfig.micOn,
        cameraOn: initialConfig.cameraOn,
        audioDeviceId: initialConfig.audioDeviceId,
        videoDeviceId: initialConfig.videoDeviceId,
        stream: initialConfig.stream
    }, isJoined)

    const [peers, setPeers] = useState<PeerData[]>([])
    const [userCount, setUserCount] = useState(0)
    const [sharingUserId, setSharingUserId] = useState<string | null>(null)
    const [hostId, setHostId] = useState<string | null>(initialHostId || null)
    const [localHandRaised, setLocalHandRaised] = useState(false)
    const [reactions, setReactions] = useState<{ id: string, emoji: string, userId: string }[]>([])
    const [mediaStatus, setMediaStatus] = useState<'connecting' | 'connected' | 'failed' | 'disconnected'>('disconnected')
    const [lastError, setLastError] = useState<string | null>(null)
    const [localScreenStream, setLocalScreenStream] = useState<MediaStream | null>(null)

    const roomRef = useRef<Room | null>(null)
    const metadataRef = useRef<UserMetadata>({
        name: userName,
        role: userRole,
        micOn: initialConfig.micOn !== false,
        cameraOn: initialConfig.cameraOn !== false,
        handRaised: false,
        language: 'floor',
        audioBlocked: false,
        isHost: false,
        isGhost: isGhostMode
    })

    const peersRef = useRef<Map<string, PeerData>>(new Map())
    const lastAudioDeviceId = useRef<string | undefined>(initialConfig.audioDeviceId)
    const lastVideoDeviceId = useRef<string | undefined>(initialConfig.videoDeviceId)

    const syncToState = useCallback(() => {
        const allPeers = Array.from(peersRef.current.values())
        // Filter: Hide ghost users UNLESS current user is an admin or MASTER
        const isAdmin = userRole === 'admin' || userRole === 'MASTER'
        const visiblePeers = allPeers.filter(p => !p.isGhost || isAdmin)
        setPeers(visiblePeers)

        if (roomRef.current) {
            // Recalculate user count based on visible peers + self (if not ghost)
            const remoteVisibleCount = allPeers.filter(p => !p.isGhost).length
            const selfVisible = isGhostMode ? 0 : 1
            setUserCount(remoteVisibleCount + selfVisible)
        } else if (isJoined) {
            setUserCount(isGhostMode ? 0 : 1)
        }
    }, [isJoined, userRole, isGhostMode])

    // --- LiveKit Room Connection ---
    useEffect(() => {
        if (!isJoined || !liveKitToken || !roomId) return

        const room = new Room({
            adaptiveStream: true,
            dynacast: true,
            publishDefaults: {
                simulcast: true, // Correct property name for Simulcast
                videoCodec: 'vp8',
                videoEncoding: {
                    maxBitrate: 800_000, // Reduced from 1.5Mbps to 800kbps for 10+ users
                    maxFramerate: 24,    // Slightly reduced for stability
                },
                screenShareEncoding: {
                    maxBitrate: 2_500_000,
                    maxFramerate: 15,    // Smooth but efficient
                }
            }
        })

        roomRef.current = room

        const handleParticipantConnected = (participant: RemoteParticipant) => {
            console.log('--- SFU Event: Participant connected:', participant.identity)
            setUserCount(room.remoteParticipants.size + 1)
        }

        const handleParticipantDisconnected = (participant: RemoteParticipant) => {
            console.log('--- SFU Event: Participant disconnected:', participant.identity)
            peersRef.current.delete(participant.identity)
            peersRef.current.delete(`${participant.identity}-presentation`)
            setUserCount(room.remoteParticipants.size + 1)
            syncToState()
        }

        const handleTrackSubscribed = (
            track: RemoteTrack,
            publication: RemoteTrackPublication,
            participant: RemoteParticipant
        ) => {
            console.log(`--- SFU Track Subscribed: ${track.kind} (${publication.source}) from ${participant.identity}`)
            const fullIdentity = participant.identity
            const userId = fullIdentity.split('_')[0]
            const isScreen = publication.source === Track.Source.ScreenShare

            const peerId = fullIdentity
            const existing = peersRef.current.get(peerId) || {
                userId,
                role: 'participant',
                connectionState: 'connected',
                joinedAt: Date.now()
            }

            if (isScreen) {
                const stream = existing.screenStream || new MediaStream()
                stream.addTrack(track.mediaStreamTrack)
                existing.screenStream = new MediaStream(stream.getTracks()) // Re-instantiate to trigger React effect
                setSharingUserId(userId)
                console.log('--- Screen Share Track Attached to Peer:', peerId, track.kind)
            } else {
                const stream = existing.stream || new MediaStream()
                // Remove existing track of same kind if already there to avoid duplicates
                stream.getTracks().forEach(t => {
                    if (t.kind === track.kind) stream.removeTrack(t)
                })
                stream.addTrack(track.mediaStreamTrack)
                existing.stream = new MediaStream(stream.getTracks()) // Re-instantiate to trigger React effect
                if (track.kind === Track.Kind.Video) existing.cameraOn = true
                if (track.kind === Track.Kind.Audio) existing.micOn = true
            }

            existing.connectionState = 'connected'
            peersRef.current.set(peerId, existing)
            syncToState()
            setUserCount(room.remoteParticipants.size + 1)
        }

        const handleTrackUnsubscribed = (
            track: RemoteTrack,
            publication: RemoteTrackPublication,
            participant: RemoteParticipant
        ) => {
            console.log(`Track unsubscribed: ${track.sid} from ${participant.identity}`)
            const peerId = participant.identity
            const existing = peersRef.current.get(peerId)
            if (existing) {
                const isScreen = publication.source === Track.Source.ScreenShare
                const stream = isScreen ? existing.screenStream : existing.stream

                if (stream) {
                    // Remove the specific track
                    stream.removeTrack(track.mediaStreamTrack)

                    // Re-instantiate the stream to trigger updates in components
                    if (stream.getTracks().length > 0) {
                        if (isScreen) {
                            existing.screenStream = new MediaStream(stream.getTracks())
                        } else {
                            existing.stream = new MediaStream(stream.getTracks())
                        }
                    } else {
                        // If no tracks left, clear the stream
                        if (isScreen) {
                            existing.screenStream = undefined
                            if (sharingUserId === participant.identity.split('_')[0]) setSharingUserId(null)
                        } else {
                            existing.stream = undefined
                        }
                    }
                }

                if (!isScreen) {
                    if (track.kind === Track.Kind.Video) existing.cameraOn = false
                    if (track.kind === Track.Kind.Audio) existing.micOn = false
                }
                peersRef.current.set(peerId, existing) // Ensure the updated peer data is set back
                syncToState()
            }
        }

        room
            .on(RoomEvent.ParticipantConnected, handleParticipantConnected)
            .on(RoomEvent.ParticipantDisconnected, handleParticipantDisconnected)
            .on(RoomEvent.TrackSubscribed, handleTrackSubscribed)
            .on(RoomEvent.TrackUnsubscribed, handleTrackUnsubscribed)
            .on(RoomEvent.TrackPublished, (pub, participant) => {
                console.log(`--- SFU Track Published: ${pub.kind} (${pub.source}) from ${participant.identity}`)
            })
            .on(RoomEvent.ConnectionStateChanged, (state) => {
                console.log('--- SFU Room Connection State:', state)
            })
            .on(RoomEvent.Disconnected, (reason) => {
                console.warn('--- SFU Room Disconnected:', reason)
                setMediaStatus('disconnected')
            })
            .on(RoomEvent.Reconnecting, () => {
                console.log('--- SFU Room Reconnecting...')
                setMediaStatus('connecting')
            })
            .on(RoomEvent.Reconnected, () => {
                console.log('--- SFU Room Reconnected')
                setMediaStatus('connected')
            })

        const connect = async () => {
            try {
                console.log('--- LiveKit Connection Attempt ---', { roomId, sessionUserId, token: !!liveKitToken })

                setMediaStatus('connecting')
                const wsUrl = process.env.NEXT_PUBLIC_LIVEKIT_URL!

                await room.connect(wsUrl, liveKitToken)
                console.log('--- LiveKit Connected Successfully ---')
                setMediaStatus('connected')
                setLastError(null)

                // Publish local tracks using LiveKit helpers (preferred)
                // This will automatically pick tracks from our localStream if they are valid
                const micEnabled = initialConfig.micOn !== false
                const camEnabled = initialConfig.cameraOn !== false

                console.log(`Setting initial media state: Mic=${micEnabled}, Cam=${camEnabled}, AudioID=${lastAudioDeviceId.current}, VideoID=${lastVideoDeviceId.current}`)
                await room.localParticipant.setMicrophoneEnabled(micEnabled, { deviceId: lastAudioDeviceId.current })
                await room.localParticipant.setCameraEnabled(camEnabled, { deviceId: lastVideoDeviceId.current })

                setUserCount(room.remoteParticipants.size + 1)
            } catch (error) {
                console.error('--- LiveKit Connection Failed ---', error)
                setLastError(error instanceof Error ? error.message : String(error))
                setMediaStatus('failed')
                setUserCount(1)
            }
        }

        connect()

        return () => {
            console.log('Cleaning up LiveKit room connection')
            room.disconnect()
        }
    }, [isJoined, liveKitToken, roomId, sessionUserId])

    // --- Signaling & Presence Logic (Metadata) ---
    const handleRoomEvent = useCallback((event: { created_by: string; type: string; payload: any }) => {
        if (event.created_by === userId) return
        const type = event.type
        const data = event.payload || {}

        if (data.targetId === userId) {
            if (type === 'KICK') {
                alert('Você foi removido da reunião pelo administrador.')
                window.location.href = '/dashboard'
            } else if (type === 'MUTE') {
                toggleMicStream(false)
                window.dispatchEvent(new CustomEvent('admin-mute'))
            } else if (type === 'BLOCK_AUDIO') {
                metadataRef.current.audioBlocked = true
                toggleMicStream(false)
                alert('Seu áudio foi bloqueado pelo anfitrião.')
            } else if (type === 'UNBLOCK_AUDIO') {
                metadataRef.current.audioBlocked = false
                alert('Seu áudio foi desbloqueado.')
            } else if (type === 'SET_ROLE') {
                metadataRef.current.role = data.role
                if (data.role !== 'interpreter') metadataRef.current.language = 'floor'
            }
            signaling?.trackMetadata(metadataRef.current)
        }

        if (type === 'SET_ALLOWED_LANGUAGES') {
            window.dispatchEvent(new CustomEvent('admin-update-languages', { detail: data.languages }))
        }
    }, [userId, toggleMicStream])

    const handlePresenceSync = useCallback((users: string[], state: Record<string, UserMetadata[]>) => {
        console.log('Presence Sync. Users in room:', users)
        let changed = false

        // 1. Remove peers that are no longer in the presence list
        const currentPeerIds = Array.from(peersRef.current.keys())
        currentPeerIds.forEach(peerId => {
            // Don't remove presentation tracks here, they are handled by LiveKit events
            if (peerId.endsWith('-presentation')) return

            if (!users.includes(peerId) && peerId !== sessionUserId) {
                console.log('Removing ghost session:', peerId)
                peersRef.current.delete(peerId)
                changed = true
            }
        })

        // 2. Add or update users that are in the presence list
        users.forEach(remoteSessionId => {
            if (remoteSessionId === sessionUserId) return
            const remoteData = (state[remoteSessionId] as any[])?.[0]
            const remoteId = remoteSessionId.split('_')[0]
            const existing = peersRef.current.get(remoteSessionId)

            if (existing) {
                let peerChanged = false
                if (remoteData?.name && existing.name !== remoteData.name) { existing.name = remoteData.name; peerChanged = true }
                if (existing.micOn !== remoteData?.micOn) { existing.micOn = !!remoteData?.micOn; peerChanged = true }
                if (existing.cameraOn !== remoteData?.cameraOn) { existing.cameraOn = !!remoteData?.cameraOn; peerChanged = true }
                if (existing.handRaised !== remoteData?.handRaised) { existing.handRaised = remoteData?.handRaised; peerChanged = true }
                // Case-insensitive role check for compatibility
                const remoteRole = remoteData?.role?.toLowerCase() || ''
                if (existing.role !== remoteRole) { existing.role = remoteRole; peerChanged = true }
                if (existing.language !== remoteData?.language) { existing.language = remoteData?.language; peerChanged = true }
                if (existing.isHost !== remoteData?.isHost) { existing.isHost = remoteData?.isHost; peerChanged = true }
                if (existing.isGhost !== remoteData?.isGhost) { existing.isGhost = remoteData?.isGhost; peerChanged = true }
                if (existing.audioBlocked !== remoteData?.audioBlocked) { existing.audioBlocked = remoteData?.audioBlocked; peerChanged = true }
                if (peerChanged) changed = true
            } else {
                console.log('Adding new session from presence:', remoteSessionId)
                // Initialize if not present (waiting for tracks)
                peersRef.current.set(remoteSessionId, {
                    userId: remoteId,
                    name: remoteData?.name || 'Participante',
                    role: remoteData?.role || 'participant',
                    micOn: remoteData?.micOn,
                    cameraOn: remoteData?.cameraOn,
                    handRaised: remoteData?.handRaised,
                    language: remoteData?.language,
                    isHost: remoteData?.isHost,
                    isGhost: remoteData?.isGhost,
                    audioBlocked: remoteData?.audioBlocked,
                    connectionState: 'connecting',
                    joinedAt: Date.now()
                })
                changed = true
            }
        })

        // 3. Cleanup: If a session is in 'connecting' for > 15 seconds 
        // AND it's not in the LiveKit room.remoteParticipants list, it's a ghost or failing.
        const now = Date.now()
        const lkParticipantIdentities = roomRef.current ? Array.from(roomRef.current.remoteParticipants.keys()) : []

        peersRef.current.forEach((peer, peerId) => {
            if (peer.isPresentation) return

            const isKnownByLK = lkParticipantIdentities.includes(peerId)
            const timeInRoom = now - (peer.joinedAt || now)

            if (!isKnownByLK && timeInRoom > 15000 && peer.connectionState === 'connecting') {
                console.warn('Presence ghost detected (15s timeout):', peerId)
                peersRef.current.delete(peerId)
                changed = true
            }
        })

        if (changed) syncToState()
    }, [sessionUserId, syncToState])

    const signaling = useSignaling(roomId, sessionUserId, metadataRef.current, {
        onSignal: () => { }, // P2P Signaling no longer needed
        onShareStarted: (payload) => setSharingUserId(payload.sender),
        onShareEnded: () => setSharingUserId(null),
        onHostPromoted: (payload) => setHostId(payload.newHostId),
        onReaction: (payload) => {
            const { emoji, sender } = payload
            const id = Math.random().toString(36).substr(2, 9)
            setReactions(prev => [...prev, { id, emoji, userId: sender }])
            setTimeout(() => setReactions(prev => prev.filter(r => r.id !== id)), 5000)
        },
        onRoomEvent: handleRoomEvent,
        onPresenceSync: handlePresenceSync
    }, isJoined)

    const updateMetadata = useCallback((patch: Partial<UserMetadata>) => {
        metadataRef.current = { ...metadataRef.current, ...patch }
        signaling?.trackMetadata(metadataRef.current)
    }, [signaling])

    // --- Restaurando Funções: Share Screen ---
    const shareScreen = async () => {
        if (!roomRef.current) return
        try {
            await roomRef.current.localParticipant.setScreenShareEnabled(true)
            // Wait a bit for the track to be published and then get the stream
            setTimeout(() => {
                const pub = roomRef.current?.localParticipant.getTrackPublication(Track.Source.ScreenShare)
                if (pub?.videoTrack?.mediaStreamTrack) {
                    const stream = new MediaStream([pub.videoTrack.mediaStreamTrack])
                    setLocalScreenStream(stream)
                }
            }, 500)
            signaling?.broadcastEvent('share-started', { sender: userId })
        } catch (error) {
            console.error('Failed to share screen:', error)
        }
    }

    const stopScreenShare = async () => {
        if (!roomRef.current) return
        try {
            await roomRef.current.localParticipant.setScreenShareEnabled(false)
            setLocalScreenStream(null)
            signaling?.broadcastEvent('share-ended', { sender: userId })
        } catch (error) {
            console.error('Failed to stop screen share:', error)
        }
    }

    const shareVideoFile = async (file: File) => {
        // Implementation for video file sharing could be added here
        console.warn('shareVideoFile not yet implemented for LiveKit')
    }

    const promoteToHost = async (newHostId: string) => {
        if (!metadataRef.current.isHost) return
        await createClient().from('meetings').update({ host_id: newHostId }).eq('id', roomId)
        signaling?.broadcastEvent('host-promoted', { newHostId })
        setHostId(newHostId)
    }

    const sendEmoji = (emoji: string) => signaling?.sendReaction(emoji)

    const toggleHand = () => {
        const newState = !localHandRaised
        setLocalHandRaised(newState)
        updateMetadata({ handRaised: newState })
    }

    const supabase = createClient()
    const kickUser = async (targetId: string) => await supabase.from('room_events').insert({ meeting_id: roomId, type: 'KICK', payload: { targetId } })
    const updateUserRole = async (targetId: string, newRole: string) => await supabase.from('room_events').insert({ meeting_id: roomId, type: 'SET_ROLE', payload: { targetId, role: newRole } })
    const updateUserLanguages = async (targetId: string, languages: string[]) => await supabase.from('room_events').insert({ meeting_id: roomId, type: 'SET_ALLOWED_LANGUAGES', payload: { targetId, languages } })
    const muteUser = async (targetId: string) => await supabase.from('room_events').insert({ meeting_id: roomId, type: 'MUTE', payload: { targetId } })
    const blockUserAudio = async (targetId: string) => await supabase.from('room_events').insert({ meeting_id: roomId, type: 'BLOCK_AUDIO', payload: { targetId } })
    const unblockUserAudio = async (targetId: string) => await supabase.from('room_events').insert({ meeting_id: roomId, type: 'UNBLOCK_AUDIO', payload: { targetId } })

    const reconnect = useCallback(() => {
        window.location.reload()
    }, [])

    const handleSwitchDevice = useCallback(async (kind: 'audio' | 'video', deviceId: string) => {
        // 1. Switch locally in our MediaStream
        await switchDevice(kind, deviceId)

        // Update refs
        if (kind === 'audio') lastAudioDeviceId.current = deviceId
        else lastVideoDeviceId.current = deviceId

        // 2. Switch in LiveKit Room if connected
        if (roomRef.current && roomRef.current.state === 'connected') {
            try {
                const lkKind: 'audioinput' | 'videoinput' = kind === 'audio' ? 'audioinput' : 'videoinput'
                await roomRef.current.switchActiveDevice(lkKind, deviceId)
                console.log(`LiveKit switched ${kind} device to:`, deviceId)
            } catch (err) {
                console.error(`LiveKit failed to switch ${kind} device:`, err)
            }
        }
    }, [switchDevice])

    const toggleMic = useCallback(async (enabled: boolean) => {
        toggleMicStream(enabled)
        if (roomRef.current) {
            await roomRef.current.localParticipant.setMicrophoneEnabled(enabled, { deviceId: lastAudioDeviceId.current })
            updateMetadata({ micOn: enabled })
        }
    }, [toggleMicStream, updateMetadata])

    const toggleCamera = useCallback(async (enabled: boolean) => {
        toggleCameraStream(enabled)
        if (roomRef.current) {
            await roomRef.current.localParticipant.setCameraEnabled(enabled, { deviceId: lastVideoDeviceId.current })
            updateMetadata({ cameraOn: enabled })
        }
    }, [toggleCameraStream, updateMetadata])

    return {
        localStream,
        peers,
        userCount: Math.max(isJoined ? 1 : 0, userCount),
        toggleMic,
        toggleCamera,
        shareScreen,
        stopScreenShare,
        shareVideoFile,
        sharingUserId,
        isAnySharing: !!sharingUserId,
        channel: signaling?.channel,
        switchDevice: handleSwitchDevice,
        sendEmoji,
        toggleHand,
        updateMetadata,
        promoteToHost,
        kickUser,
        updateUserRole,
        updateUserLanguages,
        muteUser,
        blockUserAudio,
        unblockUserAudio,
        mediaError,
        reactions,
        localHandRaised,
        hostId,
        isHost: hostId === userId,
        reconnect,
        mediaStatus,
        signalingStatus: signaling?.connectionState || 'disconnected',
        lastError,
        setLastError,
        localScreenStream
    }
}

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'

interface Term {
    id: string
    term: string
    definition?: string
}

export function useSmartGlossary(meetingId: string, textToAnalyze: string) {
    const [terms, setTerms] = useState<Term[]>([])
    const [detectedTerms, setDetectedTerms] = useState<Term[]>([])
    const [loading, setLoading] = useState(true)

    // 1. Fetch Terms
    useEffect(() => {
        if (!meetingId) return

        const fetchTerms = async () => {
            const supabase = createClient()
            const { data, error } = await supabase
                .from('glossary_terms')
                .select('*')
                .eq('meeting_id', meetingId)

            if (!error && data) {
                setTerms(data)
            }
            setLoading(false)
        }

        fetchTerms()

        // Subscription for real-time updates?
        const supabase = createClient()
        const channel = supabase.channel(`glossary:${meetingId}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'glossary_terms', filter: `meeting_id=eq.${meetingId}` },
                () => fetchTerms() // Lazy implementation: just refetch
            )
            .subscribe()

        return () => { channel.unsubscribe() }
    }, [meetingId])

    // 2. Analyze Text
    useEffect(() => {
        if (!textToAnalyze || terms.length === 0) {
            if (textToAnalyze && terms.length === 0) console.log("Glossary: Text active but NO TERMS loaded.")
            return
        }

        // Simple strict match for now. Efficient Aho-Corasick would be better for scale.
        const found = terms.filter(t => {
            const cleanTerm = t.term.trim()
            if (!cleanTerm) return false
            // Escape special regex chars in term
            const escapedTerm = cleanTerm.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            const regex = new RegExp(`\\b${escapedTerm}\\b`, 'i') // word boundary, case insensitive
            return regex.test(textToAnalyze)
        })

        if (found.length > 0) {
            console.log("Glossary: MATCH FOUND!", found.map(f => f.term))
            setDetectedTerms(prev => {
                // Add new ones to the top
                const newOnes = found.filter(f => !prev.some(p => p.id === f.id))
                return [...newOnes, ...prev].slice(0, 5) // Keep last 5 unique detected
            })
        }
    }, [textToAnalyze, terms])

    return { terms, detectedTerms, loading }
}

import { useEffect, useState, useRef, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { RealtimeChannel } from '@supabase/supabase-js'

export interface BoothState {
    partnerId: string | null
    partnerName: string | null
    // Connection state now reflects LiveKit token status or Supabase presence
    isConnected: boolean
    isHandoverPending: boolean
    handoverDeadline: number | null
    handoverRequester: string | null
    connectionState: 'idle' | 'finding-partner' | 'connecting' | 'connected' | 'disconnected'
    liveKitToken: string | null
}

export function useVirtualBooth(
    roomId: string,
    userId: string,
    userLanguage: string
) {
    const supabase = createClient()
    const [state, setState] = useState<BoothState>({
        partnerId: null,
        partnerName: null,
        isConnected: false,
        isHandoverPending: false,
        handoverDeadline: null,
        handoverRequester: null,
        connectionState: 'finding-partner',
        liveKitToken: null
    })

    const channelRef = useRef<RealtimeChannel | null>(null)
    const channelName = `booth:${roomId}:${userLanguage}`

    // 1. Get LiveKit Token
    useEffect(() => {
        if (!roomId || !userId || !userLanguage || userLanguage === 'floor') {
            setState(s => ({ ...s, liveKitToken: null }))
            return
        }

        const fetchToken = async () => {
            try {
                // Determine room name for LiveKit (one room per language booth)
                const liveKitRoom = `booth-${roomId}-${userLanguage}`
                const resp = await fetch(`/api/livekit/token?room=${liveKitRoom}&username=${userId}`)
                const data = await resp.json()
                if (data.token) {
                    setState(s => ({ ...s, liveKitToken: data.token }))
                }
            } catch (error) {
                console.error("Failed to fetch LiveKit token", error)
            }
        }
        fetchToken()
    }, [roomId, userId, userLanguage])

    // 2. Supabase Presence & Handover (Keep existing logic)
    useEffect(() => {
        if (!roomId || !userId || !userLanguage || userLanguage === 'floor') {
            setState(s => ({ ...s, connectionState: 'idle' }))
            return
        }

        const channel = supabase.channel(channelName, {
            config: { presence: { key: userId } },
        })

        channelRef.current = channel

        channel
            .on('presence', { event: 'sync' }, () => {
                const presenceState = channel.presenceState()
                const users = Object.keys(presenceState)
                const partner = users.find(id => id !== userId)

                if (partner) {
                    setState(s => ({ ...s, partnerId: partner, connectionState: 'connected' }))
                } else {
                    setState(s => ({ ...s, partnerId: null, connectionState: 'finding-partner' }))
                }
            })
            // Signaling for Handover
            .on('broadcast', { event: 'handover-request' }, ({ payload }) => {
                const { sender, deadline } = payload
                if (sender !== userId) {
                    setState(s => ({
                        ...s,
                        isHandoverPending: true,
                        handoverRequester: sender,
                        handoverDeadline: deadline
                    }))
                }
            })
            .on('broadcast', { event: 'handover-accept' }, ({ payload }) => {
                const { sender } = payload
                if (sender !== userId) {
                    window.dispatchEvent(new CustomEvent('booth-handover-accepted'))
                }
            })
            .subscribe(async (status) => {
                if (status === 'SUBSCRIBED') {
                    await channel.track({ online_at: new Date().toISOString() })
                }
            })

        return () => {
            channel.unsubscribe()
        }
    }, [roomId, userId, userLanguage, channelName])

    // Handover API
    const requestHandover = useCallback(() => {
        const deadline = Date.now() + 10000
        channelRef.current?.send({
            type: 'broadcast',
            event: 'handover-request',
            payload: { sender: userId, deadline }
        })
    }, [])

    const acceptHandover = useCallback(() => {
        channelRef.current?.send({
            type: 'broadcast',
            event: 'handover-accept',
            payload: { sender: userId }
        })
        setState(s => ({ ...s, isHandoverPending: false, handoverRequester: null }))
    }, [])

    const cancelHandover = useCallback(() => {
        setState(s => ({ ...s, isHandoverPending: false, handoverRequester: null }))
    }, [])

    return {
        ...state,
        requestHandover,
        acceptHandover,
        cancelHandover
    }
}
